 17→package org.apache.kafka.streams.processor.internals;
 18→
 19→import org.apache.kafka.common.utils.LogContext;
 20→import org.apache.kafka.streams.internals.StreamsConfigUtils.ProcessingMode;
 21→import org.apache.kafka.streams.processor.TaskId;
 22→
 23→import org.slf4j.Logger;
 24→
 25→import java.util.Collection;
 26→import java.util.HashSet;
 27→import java.util.Map;
 28→import java.util.Set;
 29→import java.util.concurrent.ConcurrentHashMap;
 30→
 31→import static org.apache.kafka.streams.processor.internals.TopologyMetadata.UNNAMED_TOPOLOGY;
 32→
 33→/**
 34→ * Multi-threaded class that tracks the status of active tasks being processed. A single instance of this class is
 35→ * shared between all StreamThreads.
 36→ */
 37→public class TaskExecutionMetadata {
 38→    // TODO: implement exponential backoff, for now we just wait 5s
 39→    private static final long CONSTANT_BACKOFF_MS = 5_000L;
 40→    private static final long NOT_READY_LOG_INTERVAL_MS = 120_000L; // Log interval of not being ready (2 minutes)
 41→
 42→    private final boolean hasNamedTopologies;
 43→    private final Set<String> pausedTopologies;
 44→    private final ProcessingMode processingMode;
 45→    private final Collection<Task> successfullyProcessed = new HashSet<>();
 46→    // map of topologies experiencing errors/currently under backoff
 47→    private final ConcurrentHashMap<String, NamedTopologyMetadata> topologyNameToErrorMetadata = new ConcurrentHashMap<>();
 48→    // map of task to last not ready logging time (not present means ready, >= 0 means not ready and tracks last log time)
 49→    private final ConcurrentHashMap<TaskId, Long> taskToLastNotReadyLogTime = new ConcurrentHashMap<>();
 50→    private final Logger log;
 51→
 52→    public TaskExecutionMetadata(final Set<String> allTopologyNames,
 53→                                 final Set<String> pausedTopologies,
 54→                                 final ProcessingMode processingMode) {
 55→        this.hasNamedTopologies = !(allTopologyNames.size() == 1 && allTopologyNames.contains(UNNAMED_TOPOLOGY));
 56→        this.pausedTopologies = pausedTopologies;
 57→        this.processingMode = processingMode;
 58→        this.log = new LogContext("").logger(TaskExecutionMetadata.class);
 59→    }
 60→
 61→    public boolean hasNamedTopologies() {
 62→        return hasNamedTopologies;
 63→    }
 64→
 65→    public ProcessingMode processingMode() {
 66→        return processingMode;
 67→    }
 68→
 69→    public boolean canProcessTask(final Task task, final long now) {
 70→        final String topologyName = task.id().topologyName();
 71→        final boolean taskWasReady = !taskToLastNotReadyLogTime.containsKey(task.id());
 72→        final boolean canProcess;
 73→        final String logMessage;
 74→        
 75→        if (!hasNamedTopologies) {
 76→            // TODO implement error handling/backoff for non-named topologies (needs KIP)
 77→            canProcess = !pausedTopologies.contains(UNNAMED_TOPOLOGY);
 78→            if (canProcess) {
 79→                logMessage = String.format("Task %s can be processed: topology is not paused", task.id());
 80→            } else {
 81→                logMessage = String.format("Task %s can't be processed: topology is paused", task.id());
 82→            }
 83→        } else {
 84→            if (pausedTopologies.contains(topologyName)) {
 85→                canProcess = false;
 86→                logMessage = String.format("Task %s can't be processed: topology '%s' is paused", task.id(), topologyName);
 87→            } else {
 88→                final NamedTopologyMetadata metadata = topologyNameToErrorMetadata.get(topologyName);
 89→                canProcess = metadata == null || (metadata.canProcess() && metadata.canProcessTask(task, now));
 90→                if (canProcess) {
 91→                    logMessage = String.format("Task %s can be processed for named topology '%s'", task.id(), topologyName);
 92→                } else {
 93→                    logMessage = String.format("Task %s can't be processed for named topology '%s'", task.id(), topologyName);
 94→                }
 95→            }
 96→        }
 97→        
 98→        if (!canProcess) {
 99→            if (taskWasReady) {
100→                // READY -> NOT_READY - start timer
101→                taskToLastNotReadyLogTime.put(task.id(), now);
102→            } else {
103→                // NOT_READY - check if it should log
104→                maybeLogNotReady(task.id(), now, logMessage);
105→            }
106→        } else {
107→            // Task is ready - clear the timer
108→            taskToLastNotReadyLogTime.remove(task.id());
109→            log.trace(logMessage);
110→        }
111→        
112→        return canProcess;
113→    }
114→    
115→    private void maybeLogNotReady(final TaskId taskId, final long now, final String logMessage) {
116→        final Long lastLogTime = taskToLastNotReadyLogTime.get(taskId);
117→        if (lastLogTime == null) {
118→            return;
119→        }
120→        
121→        final long timeSinceLastLog = now - lastLogTime;
122→        if (timeSinceLastLog >= NOT_READY_LOG_INTERVAL_MS) {
123→            log.info("Task {} is not ready to process: {}", taskId, logMessage != null ? logMessage : "Task cannot be processed");
124→            taskToLastNotReadyLogTime.put(taskId, now);
125→        }
126→    }
127→
128→    public boolean canPunctuateTask(final Task task) {
129→        final String topologyName = task.id().topologyName();
130→
131→        if (topologyName == null) {
132→            return !pausedTopologies.contains(UNNAMED_TOPOLOGY);
133→        } else {
134→            return !pausedTopologies.contains(topologyName);
135→        }
136→    }
137→
138→    public void registerTaskError(final Task task, final Throwable t, final long now) {
139→        if (hasNamedTopologies) {
140→            final String topologyName = task.id().topologyName();
141→            topologyNameToErrorMetadata.computeIfAbsent(topologyName, n -> new NamedTopologyMetadata(topologyName))
142→                .registerTaskError(task, t, now);
143→        }
144→    }
145→
146→    Collection<Task> successfullyProcessed() {
147→        return successfullyProcessed;
148→    }
149→
150→    public void addToSuccessfullyProcessed(final Task task) {
151→        successfullyProcessed.add(task);
152→    }
153→
154→    void removeTaskFromSuccessfullyProcessedBeforeClosing(final Task task) {
155→        successfullyProcessed.remove(task);
156→    }
157→
158→    void clearSuccessfullyProcessed() {
159→        successfullyProcessed.clear();
160→    }
161→    
162→    void removeTaskFromNotReadyTracking(final Task task) {
163→        final TaskId taskId = task.id();
164→        taskToLastNotReadyLogTime.remove(taskId);
165→    }
166→
167→    private class NamedTopologyMetadata {
168→        private final Logger log;
169→        private final Map<TaskId, Long> tasksToErrorTime = new ConcurrentHashMap<>();
170→
171→        public NamedTopologyMetadata(final String topologyName) {
172→            final LogContext logContext = new LogContext(String.format("topology-name [%s] ", topologyName));
173→            this.log = logContext.logger(NamedTopologyMetadata.class);
174→        }
175→
176→        public boolean canProcess() {
177→            // TODO: during long task backoffs, pause the full topology to avoid it getting out of sync
178→            return true;
179→        }
180→
181→        public boolean canProcessTask(final Task task, final long now) {
182→            final Long errorTime = tasksToErrorTime.get(task.id());
183→            if (errorTime == null) {
184→                return true;
185→            } else if (now - errorTime > CONSTANT_BACKOFF_MS) {
186→                log.info("End backoff for task {} at t={}", task.id(), now);
187→                tasksToErrorTime.remove(task.id());
188→                if (tasksToErrorTime.isEmpty()) {
189→                    topologyNameToErrorMetadata.remove(task.id().topologyName());
190→                }
191→                return true;
192→            } else {
193→                log.debug("Skipping processing for unhealthy task {} at t={}", task.id(), now);
194→                return false;
195→            }
196→        }
197→
198→        public synchronized void registerTaskError(final Task task, final Throwable t, final long now) {
199→            log.info("Begin backoff for unhealthy task {} at t={} due to {}", task.id(), now, t.getClass().getName());
200→            tasksToErrorTime.put(task.id(), now);
201→        }
202→    }
203→}
