190→    public void maybeNotifyTopologyVersionListeners() {
191→        try {
192→            lock();
193→            final long minThreadVersion = minimumThreadVersion();
194→            final Iterator<TopologyVersionListener> iterator = version.activeTopologyUpdateListeners.listIterator();
195→            TopologyVersionListener topologyVersionListener;
196→            while (iterator.hasNext()) {
197→                topologyVersionListener = iterator.next();
198→                final long topologyVersionWaitersVersion = topologyVersionListener.topologyVersion;
199→                if (minThreadVersion >= topologyVersionWaitersVersion) {
200→                    topologyVersionListener.future.complete(null);
201→                    iterator.remove();
202→                    log.info("All threads are now on topology version {}", topologyVersionListener.topologyVersion);
203→                }
204→            }
205→        } finally {
206→            unlock();
207→        }
208→    }
