 53→    public TaskExecutor(final TasksRegistry tasks,
 54→                        final TaskManager taskManager,
 55→                        final TaskExecutionMetadata executionMetadata,
 56→                        final LogContext logContext) {
 57→        this.tasks = tasks;
 58→        this.taskManager = taskManager;
 59→        this.executionMetadata = executionMetadata;
 60→        this.log = logContext.logger(getClass());
 61→    }
