 63→    /**
 64→     * @throws TaskMigratedException if the task producer got fenced (EOS only)
 65→     * @throws StreamsException      if any task threw an exception while processing
 66→     */
 67→    int process(final int maxNumRecords, final Time time) {
 68→        int totalProcessed = 0;
 69→        Task lastProcessed = null;
 70→
 71→        for (final StreamTask task : tasks.activeInitializedTasks()) {
 72→            final long now = time.milliseconds();
 73→            try {
 74→                if (executionMetadata.canProcessTask(task, now)) {
 75→                    lastProcessed = task;
 76→                    totalProcessed += processTask(task, maxNumRecords, now, time);
 77→                }
 78→            } catch (final Throwable t) {
 79→                executionMetadata.registerTaskError(task, t, now);
 80→                executionMetadata.removeTaskFromSuccessfullyProcessedBeforeClosing(lastProcessed);
 81→                commitSuccessfullyProcessedTasks();
 82→                throw t;
 83→            }
 84→        }
 85→
 86→        return totalProcessed;
 87→    }
