 89→    private int processTask(final Task task, final int maxNumRecords, final long begin, final Time time) {
 90→        int processed = 0;
 91→        long now = begin;
 92→
 93→        final long then = now;
 94→        try {
 95→            while (processed < maxNumRecords && task.process(now)) {
 96→                task.clearTaskTimeout();
 97→                processed++;
 98→            }
 99→            // TODO: enable regardless of whether using named topologies
100→            if (processed > 0 && executionMetadata.hasNamedTopologies() && executionMetadata.processingMode() != EXACTLY_ONCE_V2) {
101→                log.trace("Successfully processed task {}", task.id());
102→                executionMetadata.addToSuccessfullyProcessed(task);
103→            }
104→        } catch (final TimeoutException timeoutException) {
105→            // TODO consolidate TimeoutException retries with general error handling
106→            task.maybeInitTaskTimeoutOrThrow(now, timeoutException);
107→            log.error(
108→                String.format(
109→                    "Could not complete processing records for %s due to the following exception; will move to next task and retry later",
110→                    task.id()),
111→                timeoutException
112→            );
113→        } catch (final TaskMigratedException e) {
114→            log.info("Failed to process stream task {} since it got migrated to another thread already. " +
115→                "Will trigger a new rebalance and close all tasks as zombies together.", task.id());
116→            throw e;
117→        } catch (final StreamsException e) {
118→            log.error(String.format("Failed to process stream task %s due to the following error:", task.id()), e);
119→            e.setTaskId(task.id());
120→            throw e;
121→        } catch (final RuntimeException e) {
122→            log.error(String.format("Failed to process stream task %s due to the following error:", task.id()), e);
123→            throw new StreamsException(e, task.id());
124→        } finally {
125→            now = time.milliseconds();
126→            task.recordProcessBatchTime(now - then);
127→        }
128→        return processed;
129→    }
