131→    /**
132→     * @throws TaskMigratedException if committing offsets failed (non-EOS)
133→     *                               or if the task producer got fenced (EOS)
134→     * @throws TimeoutException if committing offsets failed due to TimeoutException (non-EOS)
135→     * @throws TaskCorruptedException if committing offsets failed due to TimeoutException (EOS)
136→     * @param consumedOffsetsAndMetadata an empty map that will be filled in with the prepared offsets
137→     * @return number of committed offsets, or -1 if we are in the middle of a rebalance and cannot commit
138→     */
139→    int commitTasksAndMaybeUpdateCommittableOffsets(final Collection<? extends Task> tasksToCommit,
140→                                                    final Map<Task, Map<TopicPartition, OffsetAndMetadata>> consumedOffsetsAndMetadata) {
141→        int committed = 0;
142→        for (final Task task : tasksToCommit) {
143→            // we need to call commitNeeded first since we need to update committable offsets
144→            if (task.commitNeeded()) {
145→                final Map<TopicPartition, OffsetAndMetadata> offsetAndMetadata = task.prepareCommit(true);
146→                if (!offsetAndMetadata.isEmpty()) {
147→                    consumedOffsetsAndMetadata.put(task, offsetAndMetadata);
148→                }
149→            }
150→        }

189→    public KafkaFuture<Void> lockTasks(final Set<TaskId> taskIds) {
190→        final KafkaFutureImpl<Void> result = new KafkaFutureImpl<>();
191→
192→        if (taskIds.isEmpty()) {
193→            result.complete(null);
194→            return result;
195→        }
196→
197→        return returnWithTasksLocked(() -> {
198→            lockedTasks.addAll(taskIds);
199→
200→            final Set<TaskId> remainingTaskIds = new ConcurrentSkipListSet<>(taskIds);
201→
202→            for (final TaskId taskId : taskIds) {
203→                final Task task = tasks.initializedTask(taskId);
204→
205→                if (task == null) {
206→                    throw new IllegalArgumentException("Trying to lock task " + taskId + " but it's not owned");
207→                }
208→
209→                if (!task.isActive()) {
210→                    throw new IllegalArgumentException("The locking task " + taskId + " is not an active task");
211→                }
212→
213→                if (assignedTasks.containsKey(taskId)) {
214→                    final TaskExecutor executor = assignedTasks.get(taskId);
215→                    log.debug("Requesting release of task {} from {}", taskId, executor.name());
216→                    final KafkaFuture<StreamTask> future = executor.unassign();
217→                    future.whenComplete((streamTask, throwable) -> {
218→                        if (throwable != null) {
219→                            result.completeExceptionally(throwable);
220→                        } else {
221→                            assert !assignedTasks.containsKey(taskId);
